                          ) : twaLogs.map((log, i) => (
                              <div key={i} className={`p-4 rounded-lg border text-xs font-mono shadow-sm ${log.level === 'error' ? 'bg-red-900/10 border-red-800' : 'bg-gray-800 border-gray-700'}`}>
