                                      <span className={`px-2 py-0.5 rounded text-[10px] uppercase font-bold ${log.level === 'error' ? 'bg-red-600 text-white' : 'bg-blue-600 text-white'}`}>
                                          {log.level}
                                      </span>
                                      <span className="text-gray-500">{new Date(log.timestamp).toLocaleString()}</span>
